import{_ as l,C as s,o as r,c as i,j as t,a,b as d,w as o,E as c,a4 as h,a2 as u}from"./chunks/framework.BtKjyiyt.js";const _=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md","lastUpdated":null}'),p={name:"architecture.md"};function g(b,e,v,m,f,k){const n=s("Mermaid");return r(),i("div",null,[e[1]||(e[1]=t("h1",{id:"architecture",tabindex:"-1"},[a("Architecture "),t("a",{class:"header-anchor",href:"#architecture","aria-label":'Permalink to "Architecture"'},"​")],-1)),e[2]||(e[2]=t("p",null,[a("KaimonSlate is layered. The source of truth is a plain "),t("code",null,".jl"),a(" file; everything else is built around keeping a reactive in-memory model, a browser view, and an evaluation kernel in sync with it.")],-1)),(r(),d(h,null,{default:o(()=>[c(n,{id:"mermaid-6",class:"mermaid",graph:"flowchart%20TB%0A%20%20file%5B(%22notebook.jl%3Cbr%2F%3E(source%20of%20truth)%22)%5D%0A%20%20subgraph%20server%5B%22NotebookServer%20(CLI-side)%22%5D%0A%20%20%20%20hub%5B%22Hub%3Cbr%2F%3Eone%20HTTP%2F2%20server%2C%20many%20notebooks%22%5D%0A%20%20%20%20live%5B%22LiveNotebook%3Cbr%2F%3Ereport%20%2B%20undo%2Fredo%20%2B%20history%20%2B%20agents%22%5D%0A%20%20%20%20engine%5B%22ReportEngine%3Cbr%2F%3Eparse%20%C2%B7%20deps%20DAG%20%C2%B7%20eval_stale!%22%5D%0A%20%20%20%20render%5B%22ReportRender%3Cbr%2F%3Eoutput_html%20%C2%B7%20markdown_html%22%5D%0A%20%20end%0A%20%20kernel%5B%22Kernel%3Cbr%2F%3EInProcess%20%C2%B7%20or%20per-notebook%20Gate%20worker%22%5D%0A%20%20browser%5B%22Browser%20SPA%3Cbr%2F%3Enotebook.html%22%5D%0A%20%20agent%5B%22AI%20agent%3Cbr%2F%3E(Kaimon%20agent%20service)%22%5D%0A%0A%20%20file%20%3C--%3E%7Cread%20%2F%20persist%20%2B%20watch%7C%20live%0A%20%20live%20--%3E%20engine%0A%20%20engine%20--%3E%20kernel%0A%20%20live%20--%3E%20render%0A%20%20live%20%3C--%3E%7CJSON%20API%20%2B%20SSE%7C%20browser%0A%20%20agent%20--%3E%7Cslate.*%20tools%7C%20live%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[a(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=u('<h2 id="Source-of-truth:-the-.jl-file" tabindex="-1">Source of truth: the <code>.jl</code> file <a class="header-anchor" href="#Source-of-truth:-the-.jl-file" aria-label="Permalink to &quot;Source of truth: the `.jl` file {#Source-of-truth:-the-.jl-file}&quot;">​</a></h2><p>A notebook is a <code>.jl</code> file with <code>#%%</code> cell headers (<code>#%% code id=…</code>, <code>#%% md id=…</code>). The server parses it into a <code>Report</code> of <code>Cell</code>s. Every in-app mutation <strong>persists back</strong> to the file, and a file-watcher pulls in <strong>external</strong> edits (VS Code, the agent writing directly, git). Because the file is canonical, the browser, your editor, and the agent never drift.</p><h2 id="ReportEngine-—-reactivity" tabindex="-1">ReportEngine — reactivity <a class="header-anchor" href="#ReportEngine-—-reactivity" aria-label="Permalink to &quot;ReportEngine — reactivity {#ReportEngine-—-reactivity}&quot;">​</a></h2><p><code>ReportEngine</code> parses cells, analyzes each cell&#39;s <strong>reads</strong> and <strong>writes</strong>, and builds a dependency DAG. <code>eval_stale!</code> recomputes only the cells marked stale, in topological order. Editing a cell marks it and its transitive dependents stale; changing a bound widget restales the readers of that variable. Async cells can call <code>slate_refresh(:x)</code> to restale readers of <code>x</code> and push a live update. See <a href="./reactivity">Reactive Cells</a>.</p><h2 id="Kernels-—-where-cells-evaluate" tabindex="-1">Kernels — where cells evaluate <a class="header-anchor" href="#Kernels-—-where-cells-evaluate" aria-label="Permalink to &quot;Kernels — where cells evaluate {#Kernels-—-where-cells-evaluate}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Kernel</th><th style="text-align:right;">When</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><code>InProcessKernel</code></td><td style="text-align:right;">Standalone notebook not inside a project</td><td style="text-align:right;">Cells eval in the server process. No separate log; no package management.</td></tr><tr><td style="text-align:right;"><code>GateKernel</code></td><td style="text-align:right;">Inside a Julia project with Kaimon&#39;s gate available</td><td style="text-align:right;">Each notebook gets its <strong>own worker process</strong>: clean namespace, tailable log, <a href="./packages">package management</a>, isolation.</td></tr></tbody></table><p>The gate worker exposes a small set of internal tools (<code>__slate_eval</code>, <code>__slate_set_bind</code>, <code>__slate_project_deps</code>, <code>__slate_pkg</code>, …) that the engine calls over the gate. The notebook namespace contract is shared between in-process and worker kernels so <code>@bind</code> and friends behave identically.</p><h2 id="NotebookServer-—-the-hub" tabindex="-1">NotebookServer — the hub <a class="header-anchor" href="#NotebookServer-—-the-hub" aria-label="Permalink to &quot;NotebookServer — the hub {#NotebookServer-—-the-hub}&quot;">​</a></h2><p>One HTTP/2 server hosts many notebooks. Routes are notebook-scoped (<code>/n/&lt;id&gt;</code> for the SPA, <code>/api/&lt;id&gt;/…</code> for JSON, <code>/api/&lt;id&gt;/events</code> for the SSE stream). The browser holds a long-lived <code>EventSource</code>; structural changes bump a version and trigger a full re-render, while value-only updates patch outputs in place (preserving editor state and scroll).</p><h2 id="ReportRender-—-output" tabindex="-1">ReportRender — output <a class="header-anchor" href="#ReportRender-—-output" aria-label="Permalink to &quot;ReportRender — output {#ReportRender-—-output}&quot;">​</a></h2><p><code>output_html</code> renders a code cell&#39;s captured value, stdout, errors, and rich display chunks (images as base64, HTML, LaTeX). <code>markdown_html</code> renders markdown cells with GFM tables, KaTeX math, and double-brace interpolation. Interactive ECharts and tables are hydrated client-side from per-cell specs. The same rendering powers <a href="./export">HTML/PDF export</a>.</p><h2 id="The-AI-agent" tabindex="-1">The AI agent <a class="header-anchor" href="#The-AI-agent" aria-label="Permalink to &quot;The AI agent {#The-AI-agent}&quot;">​</a></h2><p>When running under Kaimon, the agent is a <strong>consumer</strong> of the same surface: it drives the notebook through the <code>slate.*</code> tools (which call the agent cell ops), and its event stream is relayed onto the notebook&#39;s SSE so the chat pane updates live. A build-floor + version-CAS layer lets several agents drive one notebook safely. See <a href="./agent">The AI Agent</a>.</p>',13))])}const y=l(p,[["render",g]]);export{_ as __pageData,y as default};
